import{_ as e,c as a,o as s,ae as r}from"./chunks/framework.Cd-3tpCq.js";const h=JSON.parse('{"title":"Thème complet avec Drupal Canvas","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-canvas/index.md","filePath":"drupal-canvas/index.md"}'),n={name:"drupal-canvas/index.md"};function o(i,t,l,d,u,p){return s(),a("div",null,t[0]||(t[0]=[r(`<h1 id="theme-complet-avec-drupal-canvas" tabindex="-1">Thème complet avec Drupal Canvas <a class="header-anchor" href="#theme-complet-avec-drupal-canvas" aria-label="Permalink to &quot;Thème complet avec Drupal Canvas&quot;">​</a></h1><p><strong>Drupal Canvas</strong> est un outil de construction de pages visuelles (page builder) natif dans Drupal 11. Il permet de créer des mises en page riches en assemblant des composants directement dans le navigateur, sans écrire une seule ligne de HTML.</p><p>Cette formation vous guide de l&#39;installation jusqu&#39;à la mise en ligne d&#39;un site complet.</p><h2 id="prerequis" tabindex="-1">Prérequis <a class="header-anchor" href="#prerequis" aria-label="Permalink to &quot;Prérequis&quot;">​</a></h2><ul><li>Drupal 11 installé (voir la formation <strong>Un projet de A à Z</strong>)</li><li>Connaissances de base en HTML/CSS</li><li>Accès à l&#39;administration Drupal</li></ul><h2 id="installation-du-module-canvas" tabindex="-1">Installation du module Canvas <a class="header-anchor" href="#installation-du-module-canvas" aria-label="Permalink to &quot;Installation du module Canvas&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> require</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drupal/canvas</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drush</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> en</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> canvas</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drush</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cr</span></span></code></pre></div><p>Le choix du thème est traité dans le <strong>Module 2</strong>. Cette formation propose deux parcours :</p><table tabindex="0"><thead><tr><th>Parcours</th><th>Thème</th><th>Framework CSS</th></tr></thead><tbody><tr><td><strong>A</strong></td><td>Mercury</td><td>Tailwind CSS</td></tr><tr><td><strong>B</strong></td><td>Bootstrap Forge + Canvas Bootstrap</td><td>Bootstrap 5</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">⚠️ Thème Blank : Drupal CMS uniquement</p><p>Le thème <strong>Blank</strong> est exclusif à <strong>Drupal CMS</strong> (la distribution). Il n&#39;est pas disponible sur Drupal Core. Cette formation utilise <strong>Mercury</strong> ou <strong>Bootstrap Forge</strong> selon le parcours choisi.</p></div><h2 id="ce-que-vous-allez-apprendre" tabindex="-1">Ce que vous allez apprendre <a class="header-anchor" href="#ce-que-vous-allez-apprendre" aria-label="Permalink to &quot;Ce que vous allez apprendre&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Contenu</th></tr></thead><tbody><tr><td><strong>Module 1</strong></td><td>Comprendre Canvas : Canvas Pages, interface, types de composants</td></tr><tr><td><strong>Module 2</strong></td><td>Choisir son thème — Parcours A (Mercury/Tailwind) ou Parcours B (Bootstrap Forge)</td></tr><tr><td><strong>Module 3</strong></td><td>Créer les composants SDC : Hero, Card, Grid</td></tr><tr><td><strong>Module 4</strong></td><td>Header &amp; Footer globaux</td></tr><tr><td><strong>Module 5</strong></td><td>Construire les pages : accueil, intérieure, contact</td></tr><tr><td><strong>Module 6</strong></td><td>Pattern Components réutilisables</td></tr><tr><td><strong>Module 7</strong></td><td>Connexion aux contenus Drupal (nœuds, Views)</td></tr><tr><td><strong>Module 8</strong></td><td>Responsive, performance, accessibilité</td></tr></tbody></table><h2 id="a-qui-s-adresse-cette-formation" tabindex="-1">À qui s&#39;adresse cette formation ? <a class="header-anchor" href="#a-qui-s-adresse-cette-formation" aria-label="Permalink to &quot;À qui s&#39;adresse cette formation ?&quot;">​</a></h2><ul><li><strong>Développeurs Drupal</strong> qui souhaitent intégrer Canvas dans leurs projets</li><li><strong>Intégrateurs web</strong> qui veulent comprendre l&#39;architecture SDC</li><li><strong>Chefs de projet</strong> qui veulent autonomiser leurs clients sur la gestion des pages</li></ul><div class="tip custom-block"><p class="custom-block-title">Point de départ</p><p>Si vous débutez avec Drupal, commencez par la formation <strong>Un projet de A à Z</strong> avant de vous lancer dans cette formation Canvas.</p></div>`,15)]))}const g=e(n,[["render",o]]);export{h as __pageData,g as default};
